/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify the set of even numbers present in nums[l...r]
        const presentEvenNumbers = new Set();
        for (let i = l; i <= r; i++) {
            if (nums[i] % 2 === 0) {
                presentEvenNumbers.add(nums[i]);
            }
        }

        // 2. Determine the number of removed elements.
        // This is simply the count of distinct even numbers in nums[l...r].
        const removedCount = presentEvenNumbers.size;

        // 3. Find the k-th smallest remaining positive even number.
        // The original sequence is 2, 4, 6, 8, 10, 12, ... (the m-th positive even number is 2m).
        // If no numbers were removed, the k-th number is 2k.

        // If we remove 'd' numbers, the k-th remaining number corresponds to the (k+d)-th number in the original sequence,
        // provided that the k-th remaining number is greater than all removed numbers.

        // Let the target value be 2M.
        // The number of even numbers less than or equal to 2M is M.
        // The number of removed even numbers less than or equal to 2M is the count of elements in presentEvenNumbers
        // that are less than or equal to 2M.

        // We are looking for the smallest M such that:
        // M - (count of removed evens <= 2M) >= k

        // Since the target value 2M must be greater than or equal to the smallest possible answer,
        // we can use binary search on the answer 2M (or equivalently, on M).

        // Maximum possible answer: k is up to 10^9, removedCount is at most 10^5.
        // The target M will be around k + removedCount, so up to 10^9 + 10^5.
        // The answer 2M can be up to 2 * (10^9 + 10^5) approx 2 * 10^9.

        let low = 1;
        // A safe upper bound for M: k + removedCount (since at most removedCount evens are removed).
        // Given k <= 10^9, high = 2 * 10^9 + 1 is safe for 2M, so M up to 10^9 + 1.
        let high = k + removedCount + 1; // Upper bound for M
        let ansM = high;

        while (low <= high) {
            const M = Math.floor((low + high) / 2);
            const targetValue = 2 * M;

            // Count how many removed even numbers are less than or equal to targetValue (2M)
            let removedCountUpToM = 0;
            for (const even of presentEvenNumbers) {
                if (even <= targetValue) {
                    removedCountUpToM++;
                }
            }

            // The number of remaining even numbers less than or equal to 2M is:
            // Total evens <= 2M (which is M) - Removed evens <= 2M (removedCountUpToM)
            const remainingCount = M - removedCountUpToM;

            if (remainingCount >= k) {
                // 2M might be the answer, try for a smaller M
                ansM = M;
                high = M - 1;
            } else {
                // 2M is too small, need a larger M
                low = M + 1;
            }
        }

        results.push(2 * ansM);
    }

    return results;
}

