fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut results = Vec::new();

    for query in queries {
        let l = query[0] as usize;
        let r = query[1] as usize;
        let k = query[2];

        // 1. Identify the set of even numbers present in nums[l...r]
        let mut present_even_numbers = std::collections::HashSet::new();
        for i in l..=r {
            if nums[i] % 2 == 0 {
                present_even_numbers.insert(nums[i]);
            }
        }

        // Convert the set to a sorted vector for easier counting later
        let mut removed_evens: Vec<i64> = present_even_numbers.into_iter().collect();
        removed_evens.sort_unstable();

        // 2. Binary search on M, where the target answer is 2*M.
        // M represents the rank in the original sequence (2, 4, 6, ...).
        // We are looking for the smallest M such that the count of remaining evens <= 2M is >= k.

        // Lower bound for M is 1 (for the value 2).
        let mut low: i64 = 1;

        // Upper bound estimation: The target value 2M is roughly the k-th number plus adjustments.
        // Since at most 10^5 numbers are removed, M is around k + 10^5.
        // Given k <= 10^9, a safe upper bound for M is k + 10^5 + 1.
        // We use 2 * 10^9 + 2 for safety as i64 can hold up to ~9 * 10^18.
        let mut high: i64 = k + 100_001 + 1; 

        let mut ans_m: i64 = high;

        while low <= high {
            let m = low + (high - low) / 2;
            let target_value = 2 * m;

            // Count how many removed even numbers are less than or equal to target_value (2M)
            // Since removed_evens is sorted, we can use binary search (partition_point)
            let removed_count_up_to_m = removed_evens.partition_point(|&x| x <= target_value) as i64;

            // Total evens <= 2M is M.
            // Remaining evens <= 2M = M - removed_count_up_to_m
            let remaining_count = m - removed_count_up_to_m;

            if remaining_count >= k {
                // 2M might be the answer, try for a smaller M
                ans_m = m;
                high = m - 1;
            } else {
                // 2M is too small, need a larger M
                low = m + 1;
            }
        }

        results.push(2 * ans_m);
    }

    results
}
