use std::collections::HashSet;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut results = Vec::new();

    for query in queries {
        let l = query[0] as usize;
        let r = query[1] as usize;
        let k = query[2];

        // 1. Identify the set of even numbers present in nums[l...r]
        let mut present_even_numbers = HashSet::new();
        for i in l..=r {
            if nums[i] % 2 == 0 {
                present_even_numbers.insert(nums[i]);
            }
        }

        // Convert HashSet to a sorted vector for easier counting later
        let mut sorted_removed_evens: Vec<i64> = present_even_numbers.into_iter().collect();
        sorted_removed_evens.sort_unstable();

        // 2. Binary Search for M such that the k-th smallest remaining even number is 2M.
        // We search for M, where the target value is 2*M.

        // Low bound for M: 1 (since k >= 1)
        let mut low: i64 = 1;

        // High bound for M: A safe upper bound. The k-th remaining number is at most the (k + total_removed) -th original even number.
        // Max k is 10^9. Max total_removed is nums.len() (<= 10^5). 
        // M approx k + 10^5. 2M approx 2*10^9 + 2*10^5.
        // We use k + sorted_removed_evens.len() + 1 as a safe upper bound for M.
        let mut high: i64 = k + sorted_removed_evens.len() as i64 + 1;

        let mut ans_m: i64 = high;

        while low <= high {
            let m = low + (high - low) / 2;
            let target_value = 2 * m;

            // Count how many removed even numbers are less than or equal to targetValue (2M)
            let mut removed_count_up_to_m = 0;
            // Since sorted_removed_evens is sorted, we can count efficiently.
            // std::partition_point finds the index of the first element that does NOT satisfy the predicate (<= target_value).
            removed_count_up_to_m = sorted_removed_evens.partition_point(|&e| e <= target_value) as i64;

            // The number of remaining even numbers less than or equal to 2M is:
            // Total evens <= 2M (which is M) - Removed evens <= 2M (removedCountUpToM)
            let remaining_count = m - removed_count_up_to_m;

            if remaining_count >= k {
                // 2M is large enough (or possibly too large). This M is a potential answer. Try for a smaller M.
                ans_m = m;
                high = m - 1;
            } else {
                // 2M is too small. Need a larger M.
                low = m + 1;
            }
        }

        results.push(2 * ans_m);
    }

    results
}
